class BroadcastMode(enum.Enum):
    """
    Broadcast mode for transactions
"""
    
    SYNC = 0
    """
    Synchronous - returns after CheckTx
"""
    
    ASYNC = 1
    """
    Asynchronous - returns immediately
"""
    
    BLOCK = 2
    """
    Block - waits until transaction is included in a block
"""
    


class _UniffiFfiConverterTypeBroadcastMode(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return BroadcastMode.SYNC
        if variant == 2:
            return BroadcastMode.ASYNC
        if variant == 3:
            return BroadcastMode.BLOCK
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == BroadcastMode.SYNC:
            return
        if value == BroadcastMode.ASYNC:
            return
        if value == BroadcastMode.BLOCK:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == BroadcastMode.SYNC:
            buf.write_i32(1)
        if value == BroadcastMode.ASYNC:
            buf.write_i32(2)
        if value == BroadcastMode.BLOCK:
            buf.write_i32(3)





# MobError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class MobError(Exception):
    """
    Main error type for the mob library
"""
    pass

_UniffiTempMobError = MobError

class MobError:  # type: ignore
    """
    Main error type for the mob library
"""
    
    class Rpc(_UniffiTempMobError):
        """
        RPC-related errors
"""
        def __repr__(self):
            return "MobError.Rpc({})".format(repr(str(self)))
    _UniffiTempMobError.Rpc = Rpc # type: ignore
    class Transaction(_UniffiTempMobError):
        """
        Transaction-related errors
"""
        def __repr__(self):
            return "MobError.Transaction({})".format(repr(str(self)))
    _UniffiTempMobError.Transaction = Transaction # type: ignore
    class Signing(_UniffiTempMobError):
        """
        Signing-related errors
"""
        def __repr__(self):
            return "MobError.Signing({})".format(repr(str(self)))
    _UniffiTempMobError.Signing = Signing # type: ignore
    class KeyDerivation(_UniffiTempMobError):
        """
        Key derivation errors
"""
        def __repr__(self):
            return "MobError.KeyDerivation({})".format(repr(str(self)))
    _UniffiTempMobError.KeyDerivation = KeyDerivation # type: ignore
    class Address(_UniffiTempMobError):
        """
        Address parsing/generation errors
"""
        def __repr__(self):
            return "MobError.Address({})".format(repr(str(self)))
    _UniffiTempMobError.Address = Address # type: ignore
    class Serialization(_UniffiTempMobError):
        """
        Serialization/deserialization errors
"""
        def __repr__(self):
            return "MobError.Serialization({})".format(repr(str(self)))
    _UniffiTempMobError.Serialization = Serialization # type: ignore
    class InvalidInput(_UniffiTempMobError):
        """
        Invalid input errors
"""
        def __repr__(self):
            return "MobError.InvalidInput({})".format(repr(str(self)))
    _UniffiTempMobError.InvalidInput = InvalidInput # type: ignore
    class Account(_UniffiTempMobError):
        """
        Account-related errors
"""
        def __repr__(self):
            return "MobError.Account({})".format(repr(str(self)))
    _UniffiTempMobError.Account = Account # type: ignore
    class Network(_UniffiTempMobError):
        """
        Network-related errors
"""
        def __repr__(self):
            return "MobError.Network({})".format(repr(str(self)))
    _UniffiTempMobError.Network = Network # type: ignore
    class GasEstimation(_UniffiTempMobError):
        """
        Gas estimation errors
"""
        def __repr__(self):
            return "MobError.GasEstimation({})".format(repr(str(self)))
    _UniffiTempMobError.GasEstimation = GasEstimation # type: ignore
    class InsufficientFunds(_UniffiTempMobError):
        """
        Insufficient funds
"""
        def __repr__(self):
            return "MobError.InsufficientFunds({})".format(repr(str(self)))
    _UniffiTempMobError.InsufficientFunds = InsufficientFunds # type: ignore
    class Timeout(_UniffiTempMobError):
        """
        Timeout errors
"""
        def __repr__(self):
            return "MobError.Timeout({})".format(repr(str(self)))
    _UniffiTempMobError.Timeout = Timeout # type: ignore
    class Generic(_UniffiTempMobError):
        """
        Generic error
"""
        def __repr__(self):
            return "MobError.Generic({})".format(repr(str(self)))
    _UniffiTempMobError.Generic = Generic # type: ignore

MobError = _UniffiTempMobError # type: ignore
del _UniffiTempMobError


class _UniffiFfiConverterTypeMobError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return MobError.Rpc(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 2:
            return MobError.Transaction(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 3:
            return MobError.Signing(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 4:
            return MobError.KeyDerivation(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 5:
            return MobError.Address(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 6:
            return MobError.Serialization(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 7:
            return MobError.InvalidInput(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 8:
            return MobError.Account(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 9:
            return MobError.Network(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 10:
            return MobError.GasEstimation(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 11:
            return MobError.InsufficientFunds(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 12:
            return MobError.Timeout(
                _UniffiFfiConverterString.read(buf),
            )
        if variant == 13:
            return MobError.Generic(
                _UniffiFfiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, MobError.Rpc):
            return
        if isinstance(value, MobError.Transaction):
            return
        if isinstance(value, MobError.Signing):
            return
        if isinstance(value, MobError.KeyDerivation):
            return
        if isinstance(value, MobError.Address):
            return
        if isinstance(value, MobError.Serialization):
            return
        if isinstance(value, MobError.InvalidInput):
            return
        if isinstance(value, MobError.Account):
            return
        if isinstance(value, MobError.Network):
            return
        if isinstance(value, MobError.GasEstimation):
            return
        if isinstance(value, MobError.InsufficientFunds):
            return
        if isinstance(value, MobError.Timeout):
            return
        if isinstance(value, MobError.Generic):
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, MobError.Rpc):
            buf.write_i32(1)
        if isinstance(value, MobError.Transaction):
            buf.write_i32(2)
        if isinstance(value, MobError.Signing):
            buf.write_i32(3)
        if isinstance(value, MobError.KeyDerivation):
            buf.write_i32(4)
        if isinstance(value, MobError.Address):
            buf.write_i32(5)
        if isinstance(value, MobError.Serialization):
            buf.write_i32(6)
        if isinstance(value, MobError.InvalidInput):
            buf.write_i32(7)
        if isinstance(value, MobError.Account):
            buf.write_i32(8)
        if isinstance(value, MobError.Network):
            buf.write_i32(9)
        if isinstance(value, MobError.GasEstimation):
            buf.write_i32(10)
        if isinstance(value, MobError.InsufficientFunds):
            buf.write_i32(11)
        if isinstance(value, MobError.Timeout):
            buf.write_i32(12)
        if isinstance(value, MobError.Generic):
            buf.write_i32(13)

class _UniffiFfiConverterBytes(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        size = buf.read_i32()
        if size < 0:
            raise InternalError("Unexpected negative byte string length")
        return buf.read(size)

    @staticmethod
    def check_lower(value):
        try:
            memoryview(value)
        except TypeError:
            raise TypeError("a bytes-like object is required, not {!r}".format(type(value).__name__))

    @staticmethod
    def write(value, buf):
        buf.write_i32(len(value))
        buf.write(value)


class SignerProtocol(typing.Protocol):
    """
    A signer that manages keys and can sign transactions
"""
    
    def address(self, ) -> str:
        """
        Get the signer's address
"""
        raise NotImplementedError
    def address_prefix(self, ) -> str:
        """
        Get the address prefix
"""
        raise NotImplementedError
    def public_key_hex(self, ) -> str:
        """
        Get the signer's public key as hex
"""
        raise NotImplementedError
    def sign_bytes(self, message: bytes) -> bytes:
        """
        Sign arbitrary bytes
"""
        raise NotImplementedError

class Signer(SignerProtocol):
    """
    A signer that manages keys and can sign transactions
"""
    
    _handle: ctypes.c_uint64
    @classmethod
    def from_mnemonic(cls, mnemonic: str,address_prefix: str,derivation_path: typing.Optional[str]) -> Signer:
        """
        Create a new signer from a mnemonic phrase
"""
        
        _UniffiFfiConverterString.check_lower(mnemonic)
        
        _UniffiFfiConverterString.check_lower(address_prefix)
        
        _UniffiFfiConverterOptionalString.check_lower(derivation_path)
        _uniffi_lowered_args = (
            _UniffiFfiConverterString.lower(mnemonic),
            _UniffiFfiConverterString.lower(address_prefix),
            _UniffiFfiConverterOptionalString.lower(derivation_path),
        )
        _uniffi_lift_return = _UniffiFfiConverterTypeSigner.lift
        _uniffi_error_converter = _UniffiFfiConverterTypeMobError
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_mob_fn_constructor_signer_from_mnemonic,
            *_uniffi_lowered_args,
        )
        return cls._uniffi_make_instance(_uniffi_ffi_result)
    
    def __init__(self, *args, **kwargs):
        raise ValueError("This class has no default constructor")

    def __del__(self):
        # In case of partial initialization of instances.
        handle = getattr(self, "_handle", None)
        if handle is not None:
            _uniffi_rust_call(_UniffiLib.uniffi_mob_fn_free_signer, handle)

    def _uniffi_clone_handle(self):
        return _uniffi_rust_call(_UniffiLib.uniffi_mob_fn_clone_signer, self._handle)

    # Used by alternative constructors or any methods which return this type.
    @classmethod
    def _uniffi_make_instance(cls, handle):
        # Lightly yucky way to bypass the usual __init__ logic
        # and just create a new instance with the required handle.
        inst = cls.__new__(cls)
        inst._handle = handle
        return inst
    def address(self, ) -> str:
        """
        Get the signer's address
"""
        _uniffi_lowered_args = (
            self._uniffi_clone_handle(),
        )
        _uniffi_lift_return = _UniffiFfiConverterString.lift
        _uniffi_error_converter = None
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_mob_fn_method_signer_address,
            *_uniffi_lowered_args,
        )
        return _uniffi_lift_return(_uniffi_ffi_result)
    def address_prefix(self, ) -> str:
        """
        Get the address prefix
"""
        _uniffi_lowered_args = (
            self._uniffi_clone_handle(),
        )
        _uniffi_lift_return = _UniffiFfiConverterString.lift
        _uniffi_error_converter = None
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_mob_fn_method_signer_address_prefix,
            *_uniffi_lowered_args,
        )
        return _uniffi_lift_return(_uniffi_ffi_result)
    def public_key_hex(self, ) -> str:
        """
        Get the signer's public key as hex
"""
        _uniffi_lowered_args = (
            self._uniffi_clone_handle(),
        )
        _uniffi_lift_return = _UniffiFfiConverterString.lift
        _uniffi_error_converter = None
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_mob_fn_method_signer_public_key_hex,
            *_uniffi_lowered_args,
        )
        return _uniffi_lift_return(_uniffi_ffi_result)
    def sign_bytes(self, message: bytes) -> bytes:
        """
        Sign arbitrary bytes
"""
        
        _UniffiFfiConverterBytes.check_lower(message)
        _uniffi_lowered_args = (
            self._uniffi_clone_handle(),
            _UniffiFfiConverterBytes.lower(message),
        )
        _uniffi_lift_return = _UniffiFfiConverterBytes.lift
        _uniffi_error_converter = _UniffiFfiConverterTypeMobError
        _uniffi_ffi_result = _uniffi_rust_call_with_error(
            _uniffi_error_converter,
            _UniffiLib.uniffi_mob_fn_method_signer_sign_bytes,
            *_uniffi_lowered_args,
        )
        return _uniffi_lift_return(_uniffi_ffi_result)





class _UniffiFfiConverterTypeSigner:
    @staticmethod
    def lift(value: int) -> Signer:
        return Signer._uniffi_make_instance(value)

    @staticmethod
    def check_lower(value: Signer):
        if not isinstance(value, Signer):
            raise TypeError("Expected Signer instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: Signer) -> ctypes.c_uint64:
        return value._uniffi_clone_handle()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer) -> Signer:
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw handle value was null")
        return cls.lift(ptr)

    @classmethod
    def write(cls, value: Signer, buf: _UniffiRustBuffer):
        buf.write_u64(cls.lower(value))

class _UniffiFfiConverterBoolean:
    @classmethod
    def check_lower(cls, value):
        return not not value

    @classmethod
    def lower(cls, value):
        return 1 if value else 0

    @staticmethod
    def lift(value):
        return value != 0

    @classmethod
    def read(cls, buf):
        return cls.lift(buf.read_u8())

    @classmethod
    def write(cls, value, buf):
        buf.write_u8(value)


